#include <iostream>
#include <string>
#include <vector>

class Student {
private:
    std::string name;
    int studentID;
    static int activeStudentsCount;

public:
    Student() : name("Unknown"), studentID(0) {
        activeStudentsCount++;
    }

    Student(const std::string& n, int id) : name(n), studentID(id) {
        activeStudentsCount++;
    }

    ~Student() {
        std::cout << "Student " << name << " with ID " << studentID << " destroyed." << std::endl;
        activeStudentsCount--;
    }

    std::string getName() const { return name; }
    int getStudentID() const { return studentID; }

    static int getActiveStudentsCount() {
        return activeStudentsCount;
    }
};

int Student::activeStudentsCount = 0;

void createAndDestroyStudents() {
    Student s1("Alice", 101);
    {
        Student s2("Bob", 102);
        Student s3("Charlie", 103);
    }
    Student s4("David", 104);
}

int main() {
    std::cout << "Initial active students: " << Student::getActiveStudentsCount() << std::endl;
    Student globalStudent("GlobalStudent", 999);
    std::cout << "After global student: " << Student::getActiveStudentsCount() << std::endl;

    createAndDestroyStudents();

    std::cout << "After function call: " << Student::getActiveStudentsCount() << std::endl;

    return 0;
}
